    for (let i = 0; i < (1 << n2); i++) {
        let currentXor = 0;
        let count = 0;
        for (let j = 0; j < n2; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums2[j];
                count++;
            }
        }

        if (!map2.has(currentXor) || count < map2.get(currentXor)) {
            map2.set(currentXor, count);
        }
    }

    let maxKept = -1;

    // Combine results: We need (XOR1 ^ XOR2) = target, so XOR2 = target ^ XOR1
    for (const [xor1, count1] of map1.entries()) {
        const requiredXor2 = target ^ xor1;

